import * as React from 'react';
import type { FormProps, FormItemProps, FormRef } from '@universe-design/react';
import { Form, Input, useConstant } from '@universe-design/react';

const items = Array(100)
  .fill(0)
  .map((_, i) => i);

interface Values {
  items: number[];
}

export type ScrollToFirstErrorFieldProps = Pick<FormProps<Values>, 'shouldScrollToFirstErrorField'> &
  Pick<FormItemProps, 'noStyle'> & { autoSubmit?: boolean };

export default ({ shouldScrollToFirstErrorField, noStyle, autoSubmit = true }: ScrollToFirstErrorFieldProps) => {
  const formRef = React.useRef<FormRef<Values>>(null);
  React.useLayoutEffect(() => {
    if (autoSubmit) {
      formRef.current?.submit();
    }
  }, [autoSubmit]);

  const validateAndScrollToFirstErrorField = async () => {
    await formRef.current?.validateFields();
    formRef.current?.scrollToFirstError({ block: 'end' });
  };
  return (
    <div
      style={{
        height: '100vh',
        overflow: 'auto',
      }}
    >
      <Form<Values>
        ref={formRef}
        initialValues={useConstant(() => ({
          items,
        }))}
        {...{ shouldScrollToFirstErrorField }}
      >
        {items.map((o, i) => (
          <Form.Item
            key={i}
            name={['items', i]}
            // eslint-disable-next-line @typescript-eslint/no-magic-numbers
            validate={(v: number) => (v > 20 ? 'Item cannot be greater than 20' : undefined)}
            {...{
              noStyle,
            }}
          >
            <Input />
          </Form.Item>
        ))}
      </Form>
      <button id="scroll-to-error" onClick={validateAndScrollToFirstErrorField}>
        scroll-to-error
      </button>
    </div>
  );
};
